 1→import { type ReactNode } from 'react';
 2→import './action_panel.scss';
 3→
 4→export interface Action {
 5→  label: string;
 6→  shortcut: ReactNode;
 7→  onClick?: () => void;
 8→}
 9→
10→export interface ActionPanelProps {
11→  actions: Action[];
12→}
13→
14→export function ActionPanel({ actions }: ActionPanelProps) {
15→  const primary = actions[0];
16→  if (!primary) return null;
17→
18→  const secondary = actions.slice(1);
19→
20→  return (
21→    <footer className="action-panel" role="toolbar" aria-label="Actions">
22→      <div className="action-panel__primary">
23→        <button
24→          className="action-panel__action"
25→          onClick={primary.onClick}
26→          type="button"
27→        >
28→          <span className="action-panel__label">{primary.label}</span>
29→          <span className="action-panel__shortcut">{primary.shortcut}</span>
30→        </button>
31→      </div>
32→      {secondary.length > 0 && (
33→        <div className="action-panel__secondary">
34→          {secondary.map(action => (
35→            <button
36→              key={action.label}
